code.perFrame:
zoom = 1.0002;
rot = 0;
dx = 0;
dy = 0;
sx = 1;
sy = 1;
warp = 0.01;
cx = 0.5;
cy = 0.5;
wave_a = 0;;
//decay = 0.1;;
vol = (bass_att + treb_att + mid_att)*.333333;;
tic = min(time-tin,.1);;
tin = time;;
ra = 10;;
treb_avg = tic*(treb_avg*(1/tic - ra) + ra*treb);;
mid_avg = tic*(mid_avg*(1/tic - ra) + ra*mid);;
bass_avg = tic*(bass_avg*(1/tic - ra) + ra*bass);;
vav = tic*(vav*(1/tic - ra) + ra*(bass+treb+mid)*.33333);;
tt = tt + tic*treb_avg;;
mt = mt + tic*mid_avg;;
bt = bt + tic*bass_avg;;
sp = abs(vav - slide)*.1;;
slide = if(((slide) > (vav)),slide-tic*sp,slide+tic*sp) + (1-toc)*vav;;
toc = 1;;
vt = vt + tic*slide;;
q1 = bt;;
q2 = mt;;
q3 = tt;;
q4 = slide*1;;
q5 = vt*.05 + 150;;
q6 = .01;//tic;
